// // This module implements a 64-bit wide, 2-to-1 demultiplexer. When the select input is 0, the output result takes the value of input b; when the select input is 1, the output result takes the value of input a.
module top_module(a,b,select,result);input [63:0] a;
    input [63:0] b;
    input select;
    output[63:0] result;

     assign result = (select)? b : a;
endmodule
